      "id": "2011_kalakrishnan_stomp_stochastic_trajectory_optimization",
      "label": "STOMP",
      "title": "STOMP: Stochastic Trajectory Optimization for Motion Planning",
      "authors": [
        "Mrinal Kalakrishnan",
        "Sachin Chitta",
        "Evangelos Theodorou",
        "Peter Pastor",
        "Stefan Schaal"
      ],
      "authorShort": "Kalakrishnan, Chitta, Theodorou",
      "year": 2011,
      "source": "IEEE International Conference on Robotics and Automation (ICRA)",
      "type": "Conference Paper",
